// Transform Google Sheets response to expected format
const dadabase = $input.all();

// Find first unused joke (Used == false or empty)
const unused = dadabase.find(row => {
  const used = row.json.Used;
  return used === false || used === 'FALSE' || used === '' || used === undefined || used === null;
});

if (!unused) {
  return [{ json: { error: 'No unused jokes found', found: false } }];
}

// Extract row number (Google Sheets API returns row number in 'row' field, or calculate from index)
const rowNumber = unused.json['row'] || (dadbabase.indexOf(unused) + 2); // +2 for header row

return [{
  json: {
    row_number: rowNumber,
    'Joke ID': unused.json['Joke ID'] || unused.json['id'],
    Joke: unused.json.Joke || unused.json.joke,
    Used: false,
    Posted: unused.json.Posted || ''
  }
}];
